/// <summary>
/// Data provider for the @TaxTransactionInquiry:HeaderNote report.
/// Extends <c>SrsReportDataProviderBase</c> and populates the <c>AslXyzNoteReportAdvTmp</c> temporary table.
/// </summary>
[
    SRSReportParameterAttribute(classStr(AslXyzNoteReportAdvContract))
]
public class AslXyzNoteReportAdvDP extends SrsReportDataProviderBase
{
    AslXyzNoteReportAdvTmp aslXyzNoteReportAdvTmp;

}

Method.Source:
/// <summary>
/// Returns the temporary table buffer used by the report dataset.
/// </summary>
/// <returns>The <c>AslXyzNoteReportAdvTmp</c> table buffer.</returns>
[SRSReportDataSetAttribute(tableStr(AslXyzNoteReportAdvTmp))]
public AslXyzNoteReportAdvTmp getAslXyzNoteReportAdvTmp()
{
    select aslXyzNoteReportAdvTmp;
    return aslXyzNoteReportAdvTmp;
}

/// <summary>
/// Main data processing method. Populates the <c>AslXyzNoteReportAdvTmp</c> temporary table
/// with report data based on the contract parameters.
/// </summary>
public void processReport()
{
    AslXyzNoteReportAdvContract contract = this.parmDataContract() as AslXyzNoteReportAdvContract;
    str subjectFilter = contract.parmSubjectFilter();
    AslXyzNoteHeader noteHeader;

    if (!subjectFilter)
    {
        subjectFilter = '*';
    }

    insert_recordset aslXyzNoteReportAdvTmp (NoteId, Subject)
        select NoteId, Subject from noteHeader
            where noteHeader.Subject like subjectFilter;
}
